                                                                    # Upload to WhatsApp
                                                                    filename = f"project_notes_{datetime.now().strftime('%Y%m%d_%H%M')}.pdf"
                                                                    media_id = upload_pdf_to_whatsapp(pdf_bytes, filename)
                                                                    
